<?php use App\Helpers\Sanitizer; use App\Helpers\Url; ?>
<main class="container"><section class="module-hero"><div><span class="eyebrow">Detalle de rol</span><h1><?= Sanitizer::html($rol['nombre']) ?></h1><p><?= Sanitizer::html($rol['descripcion'] ?? '') ?></p></div><div class="action-row"><a class="btn" href="<?= Sanitizer::html(Url::ruta('/roles/editar/'.$rol['id'])) ?>">Editar</a><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/roles')) ?>">Volver</a></div></section><section class="grid-cards two-cols"><article class="card detail-card"><h2>Resumen</h2><dl><dt>Estado</dt><dd><?= (int)$rol['activo']===1?'Activo':'Inactivo' ?></dd><dt>Usuarios</dt><dd><?= (int)$rol['total_usuarios'] ?></dd><dt>Permisos</dt><dd><?= (int)$rol['total_permisos'] ?></dd><dt>Creación</dt><dd><?= Sanitizer::html($rol['fecha_creacion']) ?></dd></dl></article><article class="card"><h2>Permisos</h2><div class="chips"><?php if(empty($permisos)): ?><span class="muted">Sin permisos asignados.</span><?php endif; ?><?php foreach($permisos as $permiso): ?><span class="chip"><?= Sanitizer::html($permiso['clave']) ?></span><?php endforeach; ?></div></article></section><section class="card table-wrapper"><h2>Usuarios con este rol</h2><table><thead><tr><th>Nombre</th><th>Usuario</th><th>Correo</th><th>Estado</th></tr></thead><tbody><?php if(empty($usuarios)): ?><tr><td colspan="4" class="empty-state">Ningún usuario tiene este rol.</td></tr><?php endif; ?><?php foreach($usuarios as $usuario): ?><tr><td><?= Sanitizer::html($usuario['nombre_completo']) ?></td><td>@<?= Sanitizer::html($usuario['usuario']) ?></td><td><?= Sanitizer::html($usuario['correo']) ?></td><td><?= (int)$usuario['activo']===1?'Activo':'Inactivo' ?></td></tr><?php endforeach; ?></tbody></table></section></main>
